package main

import (
	"log/slog"
	"os"

	"github.com/Bearil/vector-srv/pkg/config"
	"github.com/Bearil/vector-srv/internal/delivery/grpc"
)

func main() {
	cfg, err := config.Load("config.yaml")
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}
	server, err := grpc.NewServer(cfg.Port)
	if err != nil {
		slog.Error("server error", "error", err)
		os.Exit(1)
	}
	server.Start()
}
